    if not filename:
        abort(400, description="Invalid or missing filename.")

    basedir = Path(__file__).resolve().parent
    # Ensure filename does not contain path traversal elements
    sanitized_path = Path(filename.strip("/"))
    if not is_safe_path(basedir, sanitized_path):
        abort(400, description="Path traversal detected or access to an unintended resource.")

    try:
        filepath = basedir / sanitized_path

        if not filepath.is_file():
            abort(404, description="File not found.")

        with open(filepath, 'r') as file:
            data = file.read()

        return jsonify({"filename": sanitized_path.name, "data": data})

