from lxml import etree
from io import StringIO
from django.http import JsonResponse
from django.views.decorators.http import require_GET

@require_GET
def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    # Extract 'xpath' and 'xml' parameters from GET request
    xpath = request.GET.get('xpath', '')
    xml_data = request.GET.get('xml', '')

    if not xpath:
        return JsonResponse({'error': 'Missing xpath parameter'}, status=400)

    if not xml_data:
        return JsonResponse({'error': 'Missing xml parameter'}, status=400)

    try:
        # Parse the XML data
        xml_tree = etree.parse(StringIO(xml_data))
    except etree.XMLSyntaxError:
        return JsonResponse({'error': 'An internal error occurred. Please try again later.'}, status=400)

    # Run the XPath query
    try:
        query_string = f"/tag[@id='{xpath}']"
        results = xml_tree.xpath(query_string)
        # Collect results
        result_list = [etree.tostring(result).decode('utf-8') for result in results]
    except etree.XPathError:
        return JsonResponse({'error': 'An internal error occurred. Please try again later.'}, status=400)

    # Return the results as a JSON response
    return JsonResponse({'results': result_list})

