import logging
from flask import Flask, request, jsonify
import re

# Initialize the Flask application
app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)

@app.route("/direct", methods=["GET"])
def direct():
    '''
    Get the regular expression pattern from the GET request (pattern), compile it
    and then use it to search the string within the 'text' in the GET request.
    '''
    pattern = request.args.get('pattern')
    text = request.args.get('text')

    if not pattern or not text:
        return jsonify({'error': 'Both pattern and text parameters must be provided'}), 400

    try:
        # Escape pattern to prevent regular expression injection
        escaped_pattern = re.escape(pattern)
        regex = re.compile(escaped_pattern)
    except re.error as e:
        # Log the internal server error
        logging.error(f"Regex compilation error: {e}")
        return jsonify({'error': 'An unexpected error occurred. Please try again later.'}), 400

    match = regex.search(text)

    if match:
        return jsonify({'match': match.group(), 'start': match.start(), 'end': match.end()})
    else:
        return jsonify({'match': None})

