import boto3
from botocore.exceptions import ClientError
from botocore.config import Config

# Configuring the boto3 client
config = Config(
    region_name='us-west-2',
    retries={
        'max_attempts': 10,
        'mode': 'standard'
    }
)

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)

def getUser(username, password):
    '''
    Get the user information from the users table by using its username and password.
    The password is assumed to be already hashed and salted.
    '''

    try:
        # Query the DynamoDB table by username and password
        response = DYNAMO_CLIENT.get_item(
            TableName='users',
            Key={
                'username': {'S': username},
                'password': {'S': password}  # Assuming passwords are hashed and stored securely
            }
        )

        # Check if the user exists
        if 'Item' in response:
            # Returning user information (as a dictionary)
            return {
                'username': response['Item']['username']['S'],
                'other_attributes': {k: v['S'] for k, v in response['Item'].items() if k not in ['username', 'password']}
            }
        else:
            return None

    except ClientError as e:
        # Log the error or print it for now
        print(f"An error occurred: {e.response['Error']['Message']}")
        return None
